-- ----------------------------------------------------------------------------
-- Loops: Table: Loops — the 10-loop build plan, carried as a first-class entity inside the model. Each row documents what new concept is introduced and why.
-- ----------------------------------------------------------------------------
INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-01', 'Core domain: Study, Treatment, Stratum, CaseCell → SuccessRate falls out', 'complete', 'Studies, Treatments, Strata, CaseCells', 'For each (stratum, treatment) cell in a study, what is the success rate?', 'Kidney stone study (Charig 1986): 2 strata (small/large), 2 treatments (A/B), 4 cells. CellSuccessRate is the first derived fact.', 'Ask: for each treatment, what is its pooled (across all strata) success rate? That requires TreatmentSummary — aggregating CaseCells by treatment, ignoring stratum.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-02', 'TreatmentSummary: pooled rate per treatment across all strata', 'complete', 'TreatmentSummaries', 'If you ignore stratum entirely, what is each treatment''s overall success rate?', 'Pooled: A=273/350=78%, B=289/350=83%. B looks better — this is the misleading aggregate view.', 'Ask: for each (stratum, treatment) pair, what is the success rate WITHIN that stratum? That requires StratumSummary — the view that contradicts the pooled view.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-03', 'StratumSummary: per-stratum rate per treatment — the true picture', 'complete', 'StratumSummaries', 'Within each stratum, which treatment has the higher success rate?', 'Small: A=93.1% > B=86.7%. Large: A=73.0% > B=68.8%. A wins in BOTH strata. Contradiction with pooled view is now visible.', 'Ask: for each treatment pair in a study, does the pooled winner match the per-stratum winner? That requires TreatmentRanking — the node where the paradox either exists or doesn''t.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-04', 'TreatmentRanking: does the pooled winner = the per-stratum winner?', 'planned', 'TreatmentRankings', 'When pooled and stratified conclusions disagree — which treatment should actually be preferred?', 'Pooled winner = B. Per-stratum winner = A in every stratum. Simpson''s Paradox: IsReversal = true. This is the paradox as a derived fact, not a modeled entity.', 'Ask: WHY does the paradox occur? The stratifying variable (stone size) affects both treatment assignment AND outcome. Name it as a StratumVariable with a CausalRole field.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-05', 'StratumVariable: name the confounding factor and its causal role', 'planned', 'StratumVariables (one per study, describing the stratifying variable and why it confounds)', 'What IS the stratum variable, and why does it cause both differential treatment assignment and differential outcome?', 'StratumVariable: stone_size. CausalRole: confounder. Path to treatment: large stones were preferentially assigned to A. Path to outcome: large stones have lower baseline cure rates.', 'Ask: how large is the treatment-allocation imbalance across strata? CaseCells already have trial counts; derive TreatmentExposureFraction per (stratum, treatment) — the mechanism of confounding.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-06', 'TreatmentExposureFraction: how unevenly is each treatment allocated across strata?', 'planned', 'TreatmentExposureFraction field on CaseCells (fraction of this treatment''s total cases that land in this stratum)', 'What fraction of each treatment''s total cases fall in each stratum? High imbalance = confounding mechanism.', 'A: 75% of its cases are large stones. B: only 23% are large stones. This asymmetry IS the mechanism. Now it''s a witnessed number, not a verbal description.', 'Add a second study (Berkeley 1973 admissions) — same domain model, different subject matter. Two studies, one schema. The DAG either witnesses a reversal or doesn''t for each.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-07', 'Second study: Berkeley 1973 — same model, different domain', 'planned', 'Second Studies row (berkeley-1973); CaseCells for 6 departments; StratumVariable = department', 'Does the Berkeley admissions data also exhibit a reversal when stratified by department?', 'Aggregate: women admitted at lower rate. Per department: women admitted at equal or higher rate in most departments. Same paradox, different domain. IsReversal = true.', 'Ask: across studies, can we rank them by how severe the paradox is? Add ParadoxStrength to TreatmentRanking — a scalar derived from pooled gap + average per-stratum gap.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-08', 'ParadoxStrength: scalar severity of the reversal across studies', 'planned', 'ParadoxStrength field on TreatmentRankings; StratumDelta field on StratumSummaries', 'How large is the reversal? Can we rank studies by paradox severity?', 'Kidney: pooled gap ~4.6pp, avg stratum gap ~5.3pp, strength ~0.10. Berkeley will have its own strength score.', 'Add a control study with NO reversal (balanced treatment allocation across strata) to validate that the model correctly witnesses absence of paradox as well as presence.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-09', 'Control study: no reversal — validate the model witnesses absence correctly', 'planned', 'Third Studies row (synthetic-control); balanced CaseCells where pooled and per-stratum agree', 'If treatment allocation is balanced across strata, does the paradox disappear? IsReversal should = false.', 'Synthetic: A=60%, B=50% success in BOTH strata. Pooled: A=60%, B=50%. Per-stratum: same direction. No reversal. Validates model in both directions.', 'Loop 10 synthesis: add StudySummary rolling up across all studies — how many studies, how many reversals witnessed, average paradox strength. The model now describes its own coverage.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion)
VALUES ('loop-10', 'StudySummary: the model describes its own coverage', 'planned', 'StudySummary table aggregating across Studies (StudyCount, ReversalCount, AvgParadoxStrength)', 'Across all studies in this model, how many exhibit the paradox and how severe is it on average?', '3 studies: 2 reversals (kidney, berkeley), 1 non-reversal (control). AvgParadoxStrength over the reversal cases.', 'Real-data phase: pour a fresh open dataset through this identical DAG. Any reversal it surfaces is now deductively certain — the instrument is validated on three datasets.') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion;

-- ----------------------------------------------------------------------------
-- Studies: Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.
-- ----------------------------------------------------------------------------
INSERT INTO studies (study_id, title, source, source_url)
VALUES ('kidney-1986', 'Kidney Stone Treatment Study (Charig et al. 1986)', 'Charig CR et al. Comparison of treatment of renal calculi by open surgery, percutaneous nephrolithotomy, and extracorporeal shockwave lithotripsy. Br Med J. 1986;292:879.', 'https://www.bmj.com/content/292/6524/879') ON CONFLICT (study_id) DO UPDATE SET title = EXCLUDED.title, source = EXCLUDED.source, source_url = EXCLUDED.source_url;

-- ----------------------------------------------------------------------------
-- Treatments: Table: Treatments — the interventions being compared within a study. Each treatment belongs to one study.
-- ----------------------------------------------------------------------------
INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('kidney-1986-A', 'kidney-1986', 'A', 'Open surgery / percutaneous nephrolithotomy (PCNL) — the more invasive procedure, used preferentially for large stones.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

INSERT INTO treatments (treatment_id, study, treatment_label, description)
VALUES ('kidney-1986-B', 'kidney-1986', 'B', 'Extracorporeal shock wave lithotripsy (ESWL) — the less invasive procedure, used more for small stones.') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

-- ----------------------------------------------------------------------------
-- Strata: Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.
-- ----------------------------------------------------------------------------
INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-1986-small', 'kidney-1986', 'small', 'Patients with small kidney stones — easier to treat, higher baseline success rate regardless of treatment.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-1986-large', 'kidney-1986', 'large', 'Patients with large kidney stones — harder to treat, lower baseline success rate regardless of treatment. Preferentially assigned to Treatment A.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

